//Copyright2015TheGoAuthors.Allrightsreserved.//UseofthissourcecodeisgovernedbyaBSD-style//licensethatcanbefoundintheLICENSEfile.packagetraceimport(	"bytes"	"fmt"	"html/template"	"io"	"log"	"net/http"	"runtime"	"sort"	"strconv"	"strings"	"sync"	"sync/atomic"	"text/tabwriter"	"time")constmaxEventsPerLog=100typebucketstruct{	MaxErrAgetime.Duration	Stringstring}varbuckets=[]bucket{	{0,"total"},	{10*time.Second,"errs<10s"},	{1*time.Minute,"errs<1m"},	{10*time.Minute,"errs<10m"},	{1*time.Hour,"errs<1h"},	{10*time.Hour,"errs<10h"},	{24000*time.Hour,"errors"},}//RenderEventsrenderstheHTMLpagetypicallyservedat/debug/events.//Itdoesnotdoanyauthchecking.Therequestmaybenil.////MostuserswillusetheEventshandler.funcRenderEvents(whttp.ResponseWriter,req*http.Request,sensitivebool){	now:=time.Now()	data:=&struct{		Families[]string//familynames		Buckets[]bucket		Counts[][]int//eventLogcountperfamily/bucket		//Setwhenabuckethasbeenselected.		Familystring		Bucketint		EventLogseventLogs		Expandedbool	}{		Buckets:buckets,	}	data.Families=make([]string,0,len(families))	famMu.RLock()	forname:=rangefamilies{		data.Families=append(data.Families,name)	}	famMu.RUnlock()	sort.Strings(data.Families)	//CountthenumberofeventLogsineachfamilyforeacherrorage.	data.Counts=make([][]int,len(data.Families))	fori,name:=rangedata.Families{		//TODO(sameer):movethisloopunderthefamilylock.		f:=getEventFamily(name)		data.Counts[i]=make([]int,len(data.Buckets))		forj,b:=rangedata.Buckets{			data.Counts[i][j]=f.Count(now,b.MaxErrAge)		}	}	ifreq!=nil{		varokbool		data.Family,data.Bucket,ok=parseEventsArgs(req)		if!ok{			//No-op		}else{			data.EventLogs=getEventFamily(data.Family).Copy(now,buckets[data.Bucket].MaxErrAge)		}		ifdata.EventLogs!=nil{			deferdata.EventLogs.Free()			sort.Sort(data.EventLogs)		}		ifexp,err:=strconv.ParseBool(req.FormValue("exp"));err==nil{			data.Expanded=exp		}	}	famMu.RLock()	deferfamMu.RUnlock()	iferr:=eventsTmpl().Execute(w,data);err!=nil{		log.Printf("net/trace:Failedexecutingtemplate:%v",err)	}}funcparseEventsArgs(req*http.Request)(famstring,bint,okbool){	fam,bStr:=req.FormValue("fam"),req.FormValue("b")	iffam==""||bStr==""{		return"",0,false	}	b,err:=strconv.Atoi(bStr)	iferr!=nil||b<0||b>=len(buckets){		return"",0,false	}	returnfam,b,true}//AnEventLogprovidesalogofeventsassociatedwithaspecificobject.typeEventLoginterface{	//Printfformatsitsargumentswithfmt.Sprintfandaddsthe	//resulttotheeventlog.	Printf(formatstring,a...interface{})	//ErrorfislikePrintf,butitmarksthiseventasanerror.	Errorf(formatstring,a...interface{})	//Finishdeclaresthatthiseventlogiscomplete.	//Theeventlogshouldnotbeusedaftercallingthismethod.	Finish()}//NewEventLogreturnsanewEventLogwiththespecifiedfamilyname//andtitle.funcNewEventLog(family,titlestring)EventLog{	el:=newEventLog()	el.ref()	el.Family,el.Title=family,title	el.Start=time.Now()	el.events=make([]logEntry,0,maxEventsPerLog)	el.stack=make([]uintptr,32)	n:=runtime.Callers(2,el.stack)	el.stack=el.stack[:n]	getEventFamily(family).add(el)	returnel}func(el*eventLog)Finish(){	getEventFamily(el.Family).remove(el)	el.unref()//matchesrefinNew}var(	famMusync.RWMutex	families=make(map[string]*eventFamily)//familyname=>family)funcgetEventFamily(famstring)*eventFamily{	famMu.Lock()	deferfamMu.Unlock()	f:=families[fam]	iff==nil{		f=&eventFamily{}		families[fam]=f	}	returnf}typeeventFamilystruct{	musync.RWMutex	eventLogseventLogs}func(f*eventFamily)add(el*eventLog){	f.mu.Lock()	f.eventLogs=append(f.eventLogs,el)	f.mu.Unlock()}func(f*eventFamily)remove(el*eventLog){	f.mu.Lock()	deferf.mu.Unlock()	fori,el0:=rangef.eventLogs{		ifel==el0{			copy(f.eventLogs[i:],f.eventLogs[i+1:])			f.eventLogs=f.eventLogs[:len(f.eventLogs)-1]			return		}	}}func(f*eventFamily)Count(nowtime.Time,maxErrAgetime.Duration)(nint){	f.mu.RLock()	deferf.mu.RUnlock()	for_,el:=rangef.eventLogs{		ifel.hasRecentError(now,maxErrAge){			n++		}	}	return}func(f*eventFamily)Copy(nowtime.Time,maxErrAgetime.Duration)(elseventLogs){	f.mu.RLock()	deferf.mu.RUnlock()	els=make(eventLogs,0,len(f.eventLogs))	for_,el:=rangef.eventLogs{		ifel.hasRecentError(now,maxErrAge){			el.ref()			els=append(els,el)		}	}	return}typeeventLogs[]*eventLog//Freecallsunrefoneachelementofthelist.func(elseventLogs)Free(){	for_,el:=rangeels{		el.unref()	}}//eventLogsmaybesortedinreversechronologicalorder.func(elseventLogs)Len()int{returnlen(els)}func(elseventLogs)Less(i,jint)bool{returnels[i].Start.After(els[j].Start)}func(elseventLogs)Swap(i,jint){els[i],els[j]=els[j],els[i]}//AlogEntryisatimestampedlogentryinaneventlog.typelogEntrystruct{	Whentime.Time	Elapsedtime.Duration//sincepreviouseventinlog	NewDaybool//whetherthiseventisonadifferentdaytothepreviousevent	Whatstring	IsErrbool}//WhenStringreturnsastringrepresentationoftheelapsedtimeoftheevent.//Itwillincludethedateifmidnightwascrossed.func(elogEntry)WhenString()string{	ife.NewDay{		returne.When.Format("2006/01/0215:04:05.000000")	}	returne.When.Format("15:04:05.000000")}//AneventLogrepresentsanactiveeventlog.typeeventLogstruct{	//Familyisthetop-levelgroupingofeventlogstowhichthisbelongs.	Familystring	//Titleisthetitleofthiseventlog.	Titlestring	//Timinginformation.	Starttime.Time	//Callstackwherethiseventlogwascreated.	stack[]uintptr	//Append-onlysequenceofevents.	//	//TODO(sameer):changethistoaringbuffertoavoidthearraycopy	//whenwehitmaxEventsPerLog.	musync.RWMutex	events[]logEntry	LastErrorTimetime.Time	discardedint	refsint32//howmanybucketsthisisin}func(el*eventLog)reset(){	//Clearallbutthemutex.Mutexesmaynotbecopied,evenwhenunlocked.	el.Family=""	el.Title=""	el.Start=time.Time{}	el.stack=nil	el.events=nil	el.LastErrorTime=time.Time{}	el.discarded=0	el.refs=0}func(el*eventLog)hasRecentError(nowtime.Time,maxErrAgetime.Duration)bool{	ifmaxErrAge==0{		returntrue	}	el.mu.RLock()	deferel.mu.RUnlock()	returnnow.Sub(el.LastErrorTime)<maxErrAge}//deltareturnstheelapsedtimesincethelasteventorthelogstart,//andwhetheritspansmidnight.//L>=el.mufunc(el*eventLog)delta(ttime.Time)(time.Duration,bool){	iflen(el.events)==0{		returnt.Sub(el.Start),false	}	prev:=el.events[len(el.events)-1].When	returnt.Sub(prev),prev.Day()!=t.Day()}func(el*eventLog)Printf(formatstring,a...interface{}){	el.printf(false,format,a...)}func(el*eventLog)Errorf(formatstring,a...interface{}){	el.printf(true,format,a...)}func(el*eventLog)printf(isErrbool,formatstring,a...interface{}){	e:=logEntry{When:time.Now(),IsErr:isErr,What:fmt.Sprintf(format,a...)}	el.mu.Lock()	e.Elapsed,e.NewDay=el.delta(e.When)	iflen(el.events)<maxEventsPerLog{		el.events=append(el.events,e)	}else{		//Discardtheoldestevent.		ifel.discarded==0{			//el.discardedstartsattwotocountfortheeventit			//isreplacing,plusthenextonethatweareaboutto			//drop.			el.discarded=2		}else{			el.discarded++		}		//TODO(sameer):ifthiscausesallocationsonacriticalpath,		//changeeventLog.Whattobeafmt.Stringer,asintrace.go.		el.events[0].What=fmt.Sprintf("(%deventsdiscarded)",el.discarded)		//Thetimestampofthediscardedmeta-eventshouldbe		//thetimeofthelasteventitisrepresenting.		el.events[0].When=el.events[1].When		copy(el.events[1:],el.events[2:])		el.events[maxEventsPerLog-1]=e	}	ife.IsErr{		el.LastErrorTime=e.When	}	el.mu.Unlock()}func(el*eventLog)ref(){	atomic.AddInt32(&el.refs,1)}func(el*eventLog)unref(){	ifatomic.AddInt32(&el.refs,-1)==0{		freeEventLog(el)	}}func(el*eventLog)When()string{	returnel.Start.Format("2006/01/0215:04:05.000000")}func(el*eventLog)ElapsedTime()string{	elapsed:=time.Since(el.Start)	returnfmt.Sprintf("%.6f",elapsed.Seconds())}func(el*eventLog)Stack()string{	buf:=new(bytes.Buffer)	tw:=tabwriter.NewWriter(buf,1,8,1,'\t',0)	printStackRecord(tw,el.stack)	tw.Flush()	returnbuf.String()}//printStackRecordprintsthefunction+sourcelineinformation//forasinglestacktrace.//Adaptedfromruntime/pprof/pprof.go.funcprintStackRecord(wio.Writer,stk[]uintptr){	for_,pc:=rangestk{		f:=runtime.FuncForPC(pc)		iff==nil{			continue		}		file,line:=f.FileLine(pc)		name:=f.Name()		//Hideruntime.goexitandanyruntimefunctionsatthebeginning.		ifstrings.HasPrefix(name,"runtime."){			continue		}		fmt.Fprintf(w,"#%s\t%s:%d\n",name,file,line)	}}func(el*eventLog)Events()[]logEntry{	el.mu.RLock()	deferel.mu.RUnlock()	returnel.events}//freeEventLogsisafreelistof*eventLogvarfreeEventLogs=make(chan*eventLog,1000)//newEventLogreturnsaeventlogreadytouse.funcnewEventLog()*eventLog{	select{	caseel:=<-freeEventLogs:		returnel	default:		returnnew(eventLog)	}}//freeEventLogaddseltofreeEventLogsifthere'sroom.//Thisisnon-blocking.funcfreeEventLog(el*eventLog){	el.reset()	select{	casefreeEventLogs<-el:	default:	}}vareventsTmplCache*template.TemplatevareventsTmplOncesync.OncefunceventsTmpl()*template.Template{	eventsTmplOnce.Do(func(){		eventsTmplCache=template.Must(template.New("events").Funcs(template.FuncMap{			"elapsed":elapsed,			"trimSpace":strings.TrimSpace,		}).Parse(eventsHTML))	})	returneventsTmplCache}consteventsHTML=`<html>	<head>		<title>events</title>	</head>	<styletype="text/css">		body{			font-family:sans-serif;		}		table#req-statustd.family{			padding-right:2em;		}		table#req-statustd.active{			padding-right:1em;		}		table#req-statustd.empty{			color:#aaa;		}		table#reqs{			margin-top:1em;		}		table#reqstr.first{			{{if$.Expanded}}font-weight:bold;{{end}}		}		table#reqstd{			font-family:monospace;		}		table#reqstd.when{			text-align:right;			white-space:nowrap;		}		table#reqstd.elapsed{			padding:00.5em;			text-align:right;			white-space:pre;			width:10em;		}		address{			font-size:smaller;			margin-top:5em;		}	</style>	<body><h1>/debug/events</h1><tableid="req-status">	{{range$i,$fam:=.Families}}	<tr>		<tdclass="family">{{$fam}}</td>{{range$j,$bucket:=$.Buckets}}{{$n:=index$.Counts$i$j}}		<tdclass="{{ifnot$bucket.MaxErrAge}}active{{end}}{{ifnot$n}}empty{{end}}">{{if$n}}<ahref="?fam={{$fam}}&b={{$j}}{{if$.Expanded}}&exp=1{{end}}">{{end}}	[{{$n}}{{$bucket.String}}]			{{if$n}}</a>{{end}}		</td>{{end}}	</tr>{{end}}</table>{{if$.EventLogs}}<hr/><h3>Family:{{$.Family}}</h3>{{if$.Expanded}}<ahref="?fam={{$.Family}}&b={{$.Bucket}}">{{end}}[Summary]{{if$.Expanded}}</a>{{end}}{{ifnot$.Expanded}}<ahref="?fam={{$.Family}}&b={{$.Bucket}}&exp=1">{{end}}[Expanded]{{ifnot$.Expanded}}</a>{{end}}<tableid="reqs">	<tr><th>When</th><th>Elapsed</th></tr>	{{range$el:=$.EventLogs}}	<trclass="first">		<tdclass="when">{{$el.When}}</td>		<tdclass="elapsed">{{$el.ElapsedTime}}</td>		<td>{{$el.Title}}	</tr>	{{if$.Expanded}}	<tr>		<tdclass="when"></td>		<tdclass="elapsed"></td>		<td><pre>{{$el.Stack|trimSpace}}</pre></td>	</tr>	{{range$el.Events}}	<tr>		<tdclass="when">{{.WhenString}}</td>		<tdclass="elapsed">{{elapsed.Elapsed}}</td>		<td>.{{if.IsErr}}E{{else}}.{{end}}.{{.What}}</td>	</tr>	{{end}}	{{end}}	{{end}}</table>{{end}}	</body></html>`